    "group_reading_level_select": "Shiraho intumbero reading urwego kuri iki group. ibirimwo will be simplified canke enriched ku match.",
    "group_visual_density_select": "Control how much ibibonwa imfashanyo umunyeshure muri iki group akira. 'Rirerire' adds vyinshi ifoto na ishusho.",
    "group_tts_speed_select": "Guhindura inyandiko-ku-speech playback umuvuduko. Slower speeds imfashanyo kurwanya readers follow along.",
    "quiz_assign_student_select": "Imura iki umunyeshure ku different group.",
    "quiz_reveal_btn": "Reveal inyishu inyishu ku vyose umunyeshure.",
