    "wizard_content_next_btn": "Proceed ku cikurikira ibirimwo creation intambwe muri umuyobozi.",
    "wizard_find_standard_btn": "Rondera kuri educational urwego ico match cawe ibirimwo ikiyago.",
    "wizard_grade_option": "Hitamwo iki urwego rw'ishuri kuri cawe isomo. Determines amajambo na igitekerezo ingorane.",
    "wizard_growth_goal_input": "Injiza learning growth intumbero kuri umunyeshure ku achieve hamwe na iki ibirimwo.",
    "wizard_instructions_input": "Ongerako gakondo amategeko kuri AI ku follow igihe kurema isomo ibirimwo.",
    "wizard_interest_add_btn": "Ongerako umunyeshure interest ikiyago ku personalize vyakozwe ibirimwo.",
    "wizard_interest_remove_btn": "Kuraho iki interest ikiyago kuva personalization urutonde.",
